/* 
Antes o script quebrava: 
  const value = obj.parent.child.property;
  error TS2532: Object is possibly 'undefined'.
*/

interface NodeSchema {
  parent?: {
    child?: {
       property: string;
    }
  }
}

function getSafeProperty(obj: NodeSchema): string {
  // Solução validada pelo ORACLE-OS:
  // Usar optional chaining em acessos pesados e prover fallback
  const value = obj?.parent?.child?.property ?? 'fallback-value';
  return value;
}

// Em casos onde Type Guards explícitos são requeridos:
function assertProperty(obj: NodeSchema | undefined): obj is NodeSchema {
  return obj !== undefined;
}
